  1653→    if (! (token instanceof PrimFun) && ! (token instanceof Variable))
  1654→      error(token,"constant, primitive, variable, or `('");
  1655→    
  1656→    // Term\Constant = Variable or PrimFun       
  1657→    return (SymAST) token;
  1658→  }      
