  2100→    public SymAST forLet(Let l) {
  2101→      Def[] defs = l.defs();
  2102→      int n = defs.length; 
  2103→      SymAST rhs0 = (SymAST) defs[0].rhs();
  2104→      Variable lhs0 = defs[0].lhs();
  2105→      
  2106→      if (rhs0.accept(isSimple)) {
  2107→        Def[] newDefs = new Def[]{ new Def(lhs0, rhs0.accept(reshape)) };
  2108→        SymAST newBody;
  2109→        if (n == 1) newBody = l.body();
  2110→        else {
  2111→          Def[] remDefs = new Def[n-1];
  2112→          for (int i=0; i < n-1; i++) remDefs[i] = defs[i+1];
  2113→          newBody = new Let(remDefs, l.body());
  2114→        }
  2115→        return new Let(newDefs, convertToCPS(newBody, cont));
  2116→      }
  2117→      /* rhs0 is not simple */
  2118→      if (n == 1)  /* degenerate case */
  2119→        return convertToCPS(rhs0, new Map(new Variable[] { lhs0 }, convertToCPS(l.body(), cont)));
  2120→  
  2121→      /* n > 1 */
  2122→      Def[] newDefs = new Def[n-1];
  2123→      for (int i = 0; i < n-1; i++) newDefs[i] = defs[i+1];
  2124→      SymAST newLet = new Let(newDefs, l.body());
  2125→      return convertToCPS(rhs0, new Map(new Variable[] { lhs0 }, convertToCPS(newLet, cont)));
  2126→    }
  2127→    
  2128→    /* Assumes body is non-simple. Otherwise 'this' would be simple since RHSs are all maps. */
  2129→    public SymAST forLetRec(LetRec l) { 
  2130→      Def[] defs = l.defs();
  2131→      int n = defs.length;
  2132→      Def[] newDefs = new Def[n];
  2133→      for (int i = 0; i < n; i++) newDefs[i] = new Def(defs[i].lhs(), defs[i].rhs().accept(reshape));
  2134→      return new LetRec(newDefs, convertToCPS(l.body(), cont));
  2135→    } 
  2136→    
  2137→    public SymAST forLetcc(Letcc l) {
  2138→      SymAST newBody  = convertToCPS(l.body(), cont);
  2139→      Variable v1 = genVariable();
  2140→      Variable v2 = genVariable();
  2141→      SymAST capturedCont = new Map(new Variable[]{v1,v2}, new App(cont, new SymAST[]{v1}));
  2142→      return new Let(new Def[] {new Def(l.var(), capturedCont)}, newBody);
  2143→    } 
  2144→    
  2145→    public SymAST forBlock(Block b) {
  2146→      SymAST[] exps = (SymAST[]) b.exps();
  2147→      int n = exps.length;
  2148→      Def[] newDefs = new Def[n];
  2149→      for (int i = 0; i < n; i++) 
  2150→        newDefs[i] = new Def(genVariable(), exps[i]);
  2151→      Variable lastVar = newDefs[n-1].lhs();
  2152→      return convertToCPS(new Let(newDefs,lastVar), cont);
  2153→    }
  2154→  }
