public JamVal forSLet(SLet sl) {
  SDAST[] rhss = sl.rhss();
  int n = rhss.length;
  JamVal[] vals = new JamVal[n];
  for (int i = 0; i < n; i++) vals[i] = rhss[i].accept(this);
  SDEnv newEnv = env.cons(vals);
  return sl.body().accept((SDASTVisitor<JamVal>) newEvalVisitor(newEnv));
}

public JamVal forSLetRec(SLetRec slr) {
  SDAST[] rhss = slr.rhss();
  int n = rhss.length;
  JamVal[] vals = new JamVal[n];
  SDEnv newEnv = env.cons(vals);
  SDASTVisitor<JamVal> newEval = newEvalVisitor(newEnv);
  for (int i = 0; i < n; i++) vals[i] = rhss[i].accept(newEval);
  return slr.body().accept(newEval);
}

