502→class SDEvaluator extends Evaluator<SDEnv> implements SDASTVisitor<JamVal> {
503→  
504→  SDEvaluator(SDEnv env) { super(env); }
505→  
506→  /*  EvalVisitor methods for evaluating SDASTs. */
507→  public SDASTVisitor<JamVal> newEvalVisitor(SDEnv env) { return new SDEvaluator(env); }
508→  public JamVal forSDPair(SDPair p)  { return env.lookup(p); }
509→  public JamVal forSMap(SMap sm) { return new SDClosure(sm, this); }
510→  public JamVal forSLet(SLet sl) {
511→    SDAST[] rhss = sl.rhss();
512→    int n = rhss.length;
513→    JamVal[] vals = new JamVal[n];
514→    for (int i = 0; i < n; i++) vals[i] = rhss[i].accept(this);
515→    SDEnv newEnv = env.cons(vals);
516→    return sl.body().accept((SDASTVisitor<JamVal>) newEvalVisitor(newEnv));
517→  }
518→  public JamVal forSLetRec(SLetRec slr) {
519→    SDAST[] rhss = slr.rhss();
520→    int n = rhss.length;
